var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"절 길러주신 신부님은 가족이나 다름없는 분이셨어요.","JPN":"私を育ててくださった神父様は、私にとっては家族も同然でした。","ENG":"The priest who raised me was like family to me.","TWN":"撫養我的神父，對我而言和家人無異。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그 분은 훗날 제가 어디에 속하게 되건, 그곳의 법도를 따라야 한다고 말씀하셨죠.","JPN":"神父様は将来私がどこに所属することになっても、そこのルールに従わねばならないと教えてくれました。","ENG":"He told me that no matter where I ended up, I had to follow the rules of that place.","TWN":"他曾說過，不論我將來歸屬哪裡，都必須遵守那裡的法則。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"제가 속한 구마회가 말하는 법도는 명료했어요.","JPN":"私が所属する祓魔会のルールは明確でした。","ENG":"The rules my exorcist order upheld were simple.","TWN":"而我所屬的驅魔會，法則非常明確。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"…악마를 멸하라.","JPN":"……悪魔を滅せよ。","ENG":"...Destroy the devils.","TWN":"……消滅魔鬼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"선봉구마사, 니콜 프라이머.","JPN":"先鋒エクソシスト、ニコル・プライマー。","ENG":"Vanguard Exorcist, Nicole Primer.","TWN":"先鋒驅魔師，妮可．布萊伊莫。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L11_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"우리에게 악마를 넘겨라.","JPN":"我らに悪魔を引き渡せ。","ENG":"Hand over the devil to us.","TWN":"把魔鬼交給我們。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그게… 갑자기 무슨 말씀이시죠?","JPN":"それは……急に何のお話でしょうか？","ENG":"W-what do you mean all of a sudden?","TWN":"你……這麼突然在說什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저는 아직 악마를 찾지 못했다고 보고를 드렸을 텐데…","JPN":"悪魔はまだ見つかっていない、と報告したはず……","ENG":"I reported that I still hadn't found any devil yet...","TWN":"我應該已經回報過，尚未找到魔鬼……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"그대는 지금 악마의 간계에 빠진 것이다.","JPN":"そなたは今悪魔の計略にはまっている。","ENG":"You have fallen for a devil's deceit.","TWN":"你已墮入魔鬼的詭計。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"그로 말미암아 자신 본질을 잊고, 악마를 감싸는 지경에 이르렀구나.","JPN":"そのせいで己の務めを忘れ、ひいては悪魔を庇うまでになってしまったようだ。","ENG":"So much so that you've forgotten your true nature and now seek to protect it.","TWN":"因此忘卻自己的本質，甚至開始包庇魔鬼。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"모든 것을 아는 성황청은 더 이상 이를 좌시하지 않기로 했으며, 그대를 대신해 규례를 행하고자 우리를 보냈음이라.","JPN":"すべてを知る聖皇庁はこれ以上この件について傍観しないと決め、そなたに代わり悪魔を祓うため我らを派遣した。","ENG":"The Holy Curia, which knows all, has decided it can no longer overlook this. We were sent to carry out the rite in your stead.","TWN":"無所不知的聖皇廳已決定不再坐視不管，派我們前來代你執行戒律。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"악마는 이곳에 없습니다.","JPN":"ここに悪魔はいません。","ENG":"There is no devil here.","TWN":"這裡沒有魔鬼。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"펜듈럼을 가지고 있다면 보여라.","JPN":"ペンデュラムを持っているのなら見せよ。","ENG":"If you possess a pendulum, present it.","TWN":"若你持有鐘擺，就拿出來。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L27_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"그것이 향하는 곳에 악마가 있을 지니.","JPN":"それが示す方向に悪魔はいるであろう。","ENG":"Where it points, the devil will be found.","TWN":"它所指之處，便是魔鬼所在。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"꺼낼 수 없겠지. 그럴 필요도 없으리라.","JPN":"取り出せるはずがない。また、その必要もない。","ENG":"You cannot bring it out. Nor is there any need.","TWN":"你拿不出來吧？其實也沒這個必要。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"그대는 이미 펜듈럼이 가리킬 방향을 알고 있을 테니.","JPN":"なぜならそなたはすでにペンデュラムが示す方向を知っているからだ。","ENG":"You already know where the pendulum would point.","TWN":"因為你早就知道鐘擺會指向哪裡。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저는 지금 뭘 하고 있는 거죠?","JPN":"私は今何をしているのでしょう？","ENG":"What am I even doing right now?","TWN":"我現在到底在做什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이렇게 계속 저항하면… 돌이킬 수 없는 문제로 퍼지고 말아요.","JPN":"こうやって抵抗し続ければ……取り返しがつかなくなってしまいます。","ENG":"If I keep resisting like this... This will spiral into something irreversible.","TWN":"再這樣抵抗下去，只會演變成無法挽回的局面。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"결국 이런 순간이 올 줄은 알았지만… 왜 하필이면 지금…","JPN":"いつかはこの瞬間が訪れるとわかっていましたが……なぜよりによって今……","ENG":"I knew this moment would come someday... But why now...?","TWN":"我早就知道會有這一天……可為什麼偏偏是現在……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그러네요. 마주하게 될 일이란 걸 알고 있었어요.","JPN":"そうですね。いつか向き合うことになるとわかってはいたんです。","ENG":"You're right. I knew I would have to face this eventually.","TWN":"是啊，我知道遲早要面對。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아직 마음의 준비가 안 됐다는 건… 안일한 변명일 뿐이겠죠.","JPN":"まだ心の準備ができていない、というのは……都合のいい言い訳に過ぎませんよね。","ENG":"Saying I'm not ready yet... is just a weak excuse.","TWN":"說自己還沒做好心理準備……也只是安逸的藉口罷了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"가게에서 소동은 용납하지 않겠습니다.","JPN":"お店で騒ぎを起こすのは許しません。","ENG":"I won't tolerate disturbance in my establishment.","TWN":"我不允許有人在店裡鬧事。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님이 아니라면… 지금 당장 나가주시죠.","JPN":"お客様でなければ……今すぐ出ていただきます。","ENG":"If you are not customers... then leave at once.","TWN":"若不是客人……請立刻離開。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"감히 무기를 겨누는가.","JPN":"我らに武器を向けるか。","ENG":"You dare raise a weapon?","TWN":"竟敢舉起武器。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L47_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"성황청이 그대에게 내린 그 무기를… 성황의 사도들에게 드리우는가?","JPN":"聖皇庁がそなたに授けたその武器を……聖皇の使徒に突きつけるというのか？","ENG":"That weapon, bestowed upon you by the Holy Curia... You would aim it at the Curia's own Apostles?","TWN":"你將聖皇廳賜予你的武器……指向聖皇的使徒嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이곳에서 저는…","JPN":"ここでの私は……","ENG":"Here, I'm...","TWN":"在這裡，我只是……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"가게를 지키는 바텐더일 뿐입니다.","JPN":"店番をしているバーテンダーにすぎません。","ENG":"Nothing more than a bartender protecting her bar.","TWN":"守護店鋪的酒保而已。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜…? 왜 그렇게 불안한 표정인 것이냐?","JPN":"ニコル……？　なぜそのような不安そうな顔をしている？","ENG":"Nicole...? Why do you look so upset?","TWN":"妮可……？你怎麼一臉不安？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이거… 타이밍이 좋지 않네요.","JPN":"これは……タイミングが悪いですね。","ENG":"This... is really bad timing.","TWN":"這時間點……真不好。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"거기에 있었나.","JPN":"そこにいたか。","ENG":"So you were there.","TWN":"原來在這裡啊。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_01"},{"id":"L11_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"신의 뜻에 따라, 악마 처단을 집행하리라.","JPN":"神の意志に従い、悪魔祓いを執行する。","ENG":"By the will of god, we shall carry out the execution of the devil.","TWN":"遵從神的旨意，執行魔鬼處刑。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_METAMOR_02"},{"id":"L14_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"힉-! 뭐, 뭐냐! 오지 마아!","JPN":"ひいっ！　な、何だ！　来るなぁ！","ENG":"Eek! W-what is that?! Don't come closer!","TWN":"咿—！什、什麼啊！別過來！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그만둬요!","JPN":"やめて！","ENG":"Stop it!","TWN":"住手！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…막아야 해.","JPN":"……止めないと。","ENG":"...I have to stop them.","TWN":"……得阻止他們。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"지금 마음을 굳히지 않으면…!","JPN":"今心を決めないと……！","ENG":"If I don't steel myself now...!","TWN":"要是現在不下定決心……！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님…?","JPN":"お客様……？","ENG":"A customer...?","TWN":"客人……？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"…아, 미안. 가게에서 소동 부리지 말랬던가?","JPN":"……あ、ごめん。お店で騒ぎを起こしちゃダメって言ってたっけ？","ENG":"...Ah, sorry. Didn't you say no disturbances in the bar?","TWN":"……啊，抱歉。不是說不要在店裡鬧事嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"근데 꼬맹이 하나 잡겠다고 달려드는 꼴을 그냥 두고 보기도 좀 그렇잖아.","JPN":"でもちびちゃん一人捕まえるからって一斉に飛びかかるとか、そんなの見過ごすわけにはいかないじゃん。","ENG":"But I couldn't just stand by and watch you rush in to grab a kid.","TWN":"我也實在看不下去，他們為了抓個小鬼就撲上來。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님이 부채를 펼쳤더니 전부 쓰러졌어.","JPN":"お客様が扇子を開いたら全員が倒れた。","ENG":"When she opened her fan, they all collapsed.","TWN":"客人一展開扇子，所有人就倒下了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"타는 냄새… 감전된 건가? 카운터 능력?","JPN":"焦げる臭い……感電させたの？　カウンター能力？","ENG":"A burning smell... Were they electrocuted? A Counter ability?","TWN":"焦味……是觸電了嗎？制裁者能力？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"어… 어떻게 된 것이냐? 이 녀석들 전부 움직이지 않는데…","JPN":"ど……どういうことだ？　こいつら全員動かなくなったが……","ENG":"W-what... happened? None of them are moving...","TWN":"這、這是怎麼回事？這些傢伙全都動不了……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모는 방으로 돌아가요!","JPN":"モモは部屋に戻ってください！","ENG":"Momo, go back to your room!","TWN":"莫莫，回房間去！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜은, 괜찮은 것이냐…?","JPN":"ニコルは、大丈夫なのか……？","ENG":"Nicole, are you okay...?","TWN":"妮可，你還好嗎……？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"전 괜찮으니 어서요!","JPN":"私はいいから早く！","ENG":"I'm fine. Hurry!","TWN":"我沒事，快走！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"으, 응…","JPN":"わ、わかった……","ENG":"O-okay...","TWN":"嗯、嗯……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"하아…","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哈啊……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"진정해, 언니. 저 꼬마가 뭘 딱히 잘못한 건 아니잖아.","JPN":"落ち着きなよ。あの子が何かしたわけでもないんだし。","ENG":"Calm down. That kid didn't really do anything wrong.","TWN":"冷靜點，姐姐。那孩子又沒做錯什麼。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"당신,","JPN":"あなた。","ENG":"You...","TWN":"你，"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"정체가 뭐죠? 지금 무슨 짓을 저지른 건지 알고는 있어요?","JPN":"何者ですか？　今自分が何をしたかわかっているんですか？","ENG":"Who are you? Do you even know what you've just done?","TWN":"你到底是什麼人？你知道自己剛才做了什麼嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"솔직하지 못하네. 방아쇠 당기기 직전이었으면서.","JPN":"素直じゃないなぁ。引き金引く寸前だったくせに。","ENG":"You're not being honest. You were about to pull the trigger.","TWN":"真不坦率。明明剛才都快扣下扳機了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"언니가 일 벌이기 전에 내가 먼저 손을 써줬으니 오히려 감사해야 하는 거 아냐?","JPN":"姉さんがやる前に私がやってあげたんだよ？　感謝してほしいね。","ENG":"I stepped in before you crossed that line. Shouldn't you be thanking me?","TWN":"我在姐姐闖禍前先出手，不該感謝我嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그건…!","JPN":"それは……！","ENG":"That's...!","TWN":"那是……！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"막아야 했던 건 맞지만… 그래도 죽여서는 안 됐어요.","JPN":"食い止めようとしたのは確かですが……それでも、殺すべきではありませんでした。","ENG":"I did need to stop them... but killing them wasn't right.","TWN":"雖然的確該阻止，但也不該殺了他們。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이 사람들은 그저 제 임무를 대신해서…","JPN":"この人たちはただ、私の代わりに任務を……","ENG":"They were just carrying out my mission in my place...","TWN":"這些人只是代替我執行任務……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"하- 누가 수녀 아니랄까봐 고집스럽긴.","JPN":"はあ、さすがシスターだけあって頭がガチガチだね。","ENG":"*Sigh...* Figures a nun would be this stubborn.","TWN":"哈—不愧是修女，真固執。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"잘 봐, 언니.","JPN":"よく見てみなさい。","ENG":"Look closely.","TWN":"你仔細看看，姐姐。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"뇌가 박살나도 움직이는 저 녀석들이, 아직도 성황청에서 온 인간들로 보여?","JPN":"脳が潰れても動いてるあいつらが、まだ聖皇庁から来た人間に見える？","ENG":"Do those things that keep moving even after their brains are smashed still look like humans from the Holy Curia to you?","TWN":"那些腦袋都爛掉還能動的傢伙，看起來還像是聖皇廳的人嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네…?","JPN":"え……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이게 무슨…?","JPN":"これはいったい……？","ENG":"What is this...?","TWN":"這是怎麼回事……？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"우우리리가가… 악마를를… 데려가겠다.","JPN":"我ラガガ……悪魔ヲヲ……連れていく。","ENG":"W-w-w-we... will take the de-de-devil.","TWN":"我、我們……要帶走……魔鬼……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"풋, 악마?","JPN":"ぷっ、悪魔だって？","ENG":"Pfft. A devil?","TWN":"噗，魔鬼？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"사탕 좋아하는 귀여운 꼬맹이 vs 뒈져도 다시 살아나는 고깃덩어리… 둘 중 어느 쪽이 더 악마에 가까울까? 지나가던 개도 아는 상식인데?","JPN":"キャンディが好きな可愛いちびちゃんと、くたばっても蘇る肉の塊……どっちが悪魔に近いんだろうね？　バカでもわかるでしょ。","ENG":"A candy-loving little kid versus a chunk of meat that keeps moving even after it dies... which one sounds more like a devil? Even a stray dog could answer that.","TWN":"愛吃糖的可愛小孩vs就算死了也會復活的肉塊……哪個比較像魔鬼？連路過的狗都知道吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…듣듣고 이르되되, 수확의 때가 도래하였으니.","JPN":"……我ラ聞キテイワク、収穫の時は到来した。","ENG":"...Hearken and heed, for the time of harvest has come.","TWN":"……願聞其之，收穫之時已到來。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L29_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"작은 왕을 찾아 이방의 악마가 암군을 기만치 못하게 하라.","JPN":"小さき王を見つけ出し、異邦の悪魔が暗君を欺くことを阻止せよ。","ENG":"Find the little queen, and see that the foreign devil deceives the Ignorant Monarch no longer.","TWN":"尋找小王，莫讓異邦的惡魔欺瞞暗軍。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"…하아-","JPN":"……はあ。","ENG":"*Sigh...*","TWN":"……哈啊—"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"저것들. 본색을 드러낼 땐 항상 저런 식으로 뭔지 모를 소릴 지껄인단 말이지.","JPN":"あいつら、正体を現すといつもあんな感じでわけのわからないことばっかり喋るんだよね。","ENG":"Those things. Whenever they show their true colors, they always start babbling nonsense like that.","TWN":"那些傢伙，每次露出真面目就會講些莫名其妙的話。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"여긴 내가 맡을 테니 언니도 얼른 방으로 숨어…","JPN":"ここは私に任せて、姉さんも早く部屋に隠れ……","ENG":"I'll handle this. You hurry and hide in the back–","TWN":"這裡交給我，姐姐也快躲進房間……"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…다행이네요.","JPN":"……よかったです。","ENG":"...That's a relief.","TWN":"……太好了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"응? 이 상황에 갑자기?","JPN":"ん？　この状況で急に？","ENG":"Huh? Now of all times?","TWN":"嗯？這種情況下這麼突然？"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저 사람들. 성황청에서 온 분들이 아니었군요.","JPN":"あの人たち、聖皇庁から来た方々じゃなかったんですね。","ENG":"Those people... they weren't really from the Holy Curia after all.","TWN":"那些人，原來不是聖皇廳的人啊。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럼, 저도 망설일 필요가 없죠.","JPN":"それなら、迷う理由はありません。","ENG":"Then I don't need to hesitate anymore.","TWN":"那我也沒必要再猶豫了。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L42_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"잠깐, 저것들은 사람이 아니라 괴물에 가깝다고. 그런 골동품 총으로 제압할 생각은…","JPN":"あのね、あいつらは人間じゃなくて化け物に近いんだよ。そんな古い銃じゃ……","ENG":"Wait, those things are closer to monsters than people. You're not planning to handle them with that antique gun–","TWN":"等等，那些東西已經不能算人了，用那種老古董槍真的能……"},"stage":{"bg":"GREMORY_BAR","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"…통하잖아?","JPN":"……効いた？","ENG":"...It works?","TWN":"……有效耶？"},"stage":{"bg":"GREMORY_BAR","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"뒤쪽에서도 와요!","JPN":"後ろからも来ます！","ENG":"They're coming from the back, too!","TWN":"後面也追上了！"},"stage":{"bg":"GREMORY_BAR","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"말 안 해줘도 알거든?","JPN":"言われなくてもわかってる！","ENG":"You didn't have to tell me!","TWN":"不用說我也知道！"},"stage":{"bg":"GREMORY_BAR","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINHA_G1_STUDENT_NULL","text":{"KOREA":"그럼 그쪽은 맡긴다!","JPN":"じゃあそっちは任せた！","ENG":"Then I'll take that side!","TWN":"那邊就交給你了！"},"stage":{"bg":"GREMORY_BAR","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_STUDENT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};